#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding psychiatry-assessment (16 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_presenting_complaint \
    assessment:references \
    chief_complaint:text! \
    onset_date:date \
    onset_description:string! \
    duration:text! \
    severity:string! \
    precipitating_factors:text! \
    aggravating_factors:text! \
    relieving_factors:text! \
    previous_episodes:string! \
    previous_episode_details:text! \
    referral_source:string! \
    referral_reason:text! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_psychiatric_history \
    assessment:references \
    previous_diagnoses:text! \
    age_first_contact:int \
    previous_inpatient_admissions:string! \
    inpatient_admission_count:int \
    inpatient_details:text! \
    previous_sectioning:string! \
    sectioning_details:text! \
    previous_ect:string! \
    previous_therapy:string! \
    therapy_types:text! \
    therapy_response:string! \
    previous_medication_trials:text! \
    treatment_adherence:string! \
    longest_period_of_wellness:text! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_mental_status_exam \
    assessment:references \
    appearance:text! \
    behaviour:string! \
    psychomotor_activity:string! \
    speech_rate:string! \
    speech_volume:string! \
    speech_quality:string! \
    mood_subjective:text! \
    affect:string! \
    affect_congruence:string! \
    thought_form:string! \
    thought_content:text! \
    delusions:string! \
    delusion_details:text! \
    hallucinations:string! \
    hallucination_type:string! \
    hallucination_details:text! \
    orientation_time:string! \
    orientation_place:string! \
    orientation_person:string! \
    concentration:string! \
    memory_short_term:string! \
    memory_long_term:string! \
    insight:string! \
    judgement:string! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_risk_assessment \
    assessment:references \
    suicidal_ideation:string! \
    suicidal_ideation_details:text! \
    suicidal_plan:string! \
    suicidal_plan_details:text! \
    suicidal_intent:string! \
    access_to_means:string! \
    means_details:text! \
    previous_suicide_attempts:string! \
    attempt_count:int \
    attempt_details:text! \
    self_harm_current:string! \
    self_harm_details:text! \
    risk_to_others:string! \
    risk_to_others_details:text! \
    violence_history:string! \
    violence_details:text! \
    vulnerability:string! \
    vulnerability_details:text! \
    safeguarding_concerns:string! \
    safeguarding_details:text! \
    protective_factors:text! \
    overall_risk_level:string! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_mood_and_anxiety \
    assessment:references \
    phq9_score:int \
    gad7_score:int \
    depressed_mood:string! \
    anhedonia:string! \
    sleep_disturbance:string! \
    appetite_change:string! \
    energy_level:string! \
    concentration_difficulty:string! \
    psychomotor_changes:string! \
    guilt_worthlessness:string! \
    panic_attacks:string! \
    panic_frequency:text! \
    phobias:string! \
    phobia_details:text! \
    obsessions:string! \
    compulsions:string! \
    ocd_details:text! \
    ptsd_symptoms:string! \
    ptsd_details:text! \
    manic_episodes:string! \
    manic_episode_details:text! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_substance_use \
    assessment:references \
    alcohol_use:string! \
    alcohol_units_per_week:int \
    audit_score:int \
    tobacco_use:string! \
    cigarettes_per_day:int \
    cannabis_use:string! \
    stimulant_use:string! \
    stimulant_details:text! \
    opioid_use:string! \
    opioid_details:text! \
    benzodiazepine_misuse:string! \
    novel_psychoactive_substances:string! \
    iv_drug_use:string! \
    previous_detox:string! \
    previous_detox_details:text! \
    substance_use_impact:text! \
    motivation_to_change:string! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_current_medications \
    assessment:references \
    takes_psychiatric_medications:string! \
    takes_other_medications:string! \
    medication_adherence:string! \
