    side_effects:text! \
    clozapine_registered:string! \
    depot_injection:string! \
    depot_details:text! \
    adverse_drug_reactions:text! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_medication_item \
    current_medications:references \
    medication_name:string! \
    dose:string! \
    frequency:string! \
    medication_type:string! \
    indication:text! \
    prescribing_clinician:string! \
    sort_order:int! \
    --htmx

cargo loco generate scaffold assessment_medical_history \
    assessment:references \
    chronic_conditions:text! \
    neurological_conditions:string! \
    neurological_details:text! \
    endocrine_conditions:string! \
    endocrine_details:text! \
    cardiovascular_conditions:string! \
    cardiovascular_details:text! \
    head_injuries:string! \
    head_injury_details:text! \
    seizure_history:string! \
    known_allergies:string! \
    allergy_details:text! \
    recent_blood_tests:string! \
    blood_test_results:text! \
    physical_health_screening:string! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_social_history \
    assessment:references \
    living_arrangement:string! \
    living_arrangement_details:text! \
    relationship_status:string! \
    dependants:string! \
    dependant_details:text! \
    employment_status:string! \
    occupation:string! \
    financial_difficulties:string! \
    benefits_received:text! \
    forensic_history:string! \
    forensic_details:text! \
    current_legal_issues:string! \
    legal_details:text! \
    immigration_status:string! \
    social_support:text! \
    hobbies_interests:text! \
    spiritual_beliefs:text! \
    childhood_adversity:string! \
