    additional_notes:text! \
    --htmx

cargo loco generate scaffold assessment_capacity_and_consent \
    assessment:references \
    capacity_assessed:string! \
    has_capacity:string! \
    understands_information:string! \
    retains_information:string! \
    weighs_information:string! \
    communicates_decision:string! \
    capacity_details:text! \
    advance_directive:string! \
    advance_directive_details:text! \
    lasting_power_of_attorney:string! \
    lpa_details:text! \
    mental_health_act_status:string! \
    mha_details:text! \
    consent_to_treatment:string! \
    consent_to_share_information:string! \
    nearest_relative:string! \
    nearest_relative_informed:string! \
    additional_notes:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    gaf_score:int! \
    gaf_category:string! \
    symptom_severity:string! \
    functional_impairment:string! \
    risk_classification:string! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    gaf_impact:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
